import satori from 'satori';
import { html } from 'satori-html';
import {  Resvg } from '@resvg/resvg-wasm';

export class ImageResponse extends Response {
  constructor(markup, { width = 1200, height = 630, debug = false, fonts = [], ...opts } = {}) {
    const stream = new ReadableStream({
      start: async (controller) => {
        markup = await markup;
        const opts = await import('./assets/index.mjs').then(res => res.default());
        fonts.push(...opts.fonts);
        const svg = await satori(typeof markup === 'string' ? html(markup) : markup, {
          width,
          height,
          debug,
          fonts,
        })
        const image = new Resvg(svg, { fitTo: { mode: 'width', value: width } })
        const chunk = image.render().asPng()
        controller.enqueue(chunk);
        controller.close();
      }
    })

    super(stream, {
        headers: { 
          "content-type":"image/png",
          "cache-control": debug ? "no-cache, no-store" : "public, immutable, no-transform, max-age=31536000",
          ...opts.headers
        }, 
        status: opts.status, 
        statusText: opts.statusText 
      })
    }
}
